// ============================================================================
// Sample Loans (V8 version)
// ============================================================================
function TabSampleLoans({ md }) {
  const sample = md.sample_loans || [];
  const [sortKey, setSortKey] = useState('pred_cpr');
  const [sortDesc, setSortDesc] = useState(true);
  const multNames = sample.length ? Object.keys(sample[0].multipliers || {}) : [];

  const getValue = (row, key) => {
    if (key.startsWith('attr_')) return row.attribution[key.slice(5)];
    if (multNames.includes(key)) return row.multipliers[key];
    return row[key];
  };
  const sorted = useMemo(() => {
    const list = [...sample];
    list.sort((a, b) => {
      const av = getValue(a, sortKey);
      const bv = getValue(b, sortKey);
      if (typeof av === 'string') return sortDesc ? bv.localeCompare(av) : av.localeCompare(bv);
      return sortDesc ? (bv - av) : (av - bv);
    });
    return list;
  }, [sample, sortKey, sortDesc, multNames.length]);

  const flipSort = k => {
    if (sortKey === k) setSortDesc(!sortDesc);
    else { setSortKey(k); setSortDesc(true); }
  };
  const arrow = k => sortKey === k ? (sortDesc ? ' ▼' : ' ▲') : '';
  const attrColor = v => (v == null) ? T.textDim
    : v > 0.5 ? T.green : v < -0.5 ? T.red : T.textDim;

  if (!sample.length) {
    return <Panel title="Sample Loans">
      <div style={{ color: T.textDim, fontSize: 12 }}>
        No sample_loans. Run <span style={{fontFamily: FONT_MONO}}>train_v8.py --emit-dashboard</span>.
      </div>
    </Panel>;
  }

  const cellTd = { padding: '4px 6px', borderBottom: `1px solid ${T.border}` };
  const headTd = { ...cellTd, background: T.panelLight, color: T.text, cursor: 'pointer',
                   textAlign: 'left', whiteSpace: 'nowrap', fontWeight: 600,
                   borderBottom: `2px solid ${T.border}`, position: 'sticky', top: 0 };

  const groups = [
    { bg: T.panelLight, cols: [
      ['loan_id', 'Loan ID', 'text'], ['pool_cusip', 'Pool', 'text'],
      ['period', 'Period', 'date'], ['cohort_id', 'Cohort', 'text'],
      ['fha_category', 'FHA', 'text'], ['loan_purpose', 'Purp', 'text'],
      ['issuer', 'Issuer', 'text'], ['state', 'St', 'text']]},
    { bg: '#0E3A5F', cols: [
      ['coupon_pct', 'Coupon%', 'num'], ['plc_pct', 'PLC%', 'num'],
      ['vintage', 'Vintage', 'num'], ['origination', 'Orig', 'date'],
      ['maturity_date', 'Maturity', 'date'], ['orig_term_mo', 'Term(mo)', 'num'],
      ['num_units', 'Units', 'num'], ['orig_upb_M', 'OrigUPB$M', 'num']]},
    { bg: '#5C2A1A', cols: [
      ['lockout_yrs', 'LkYrs', 'num'], ['prepay_yrs', 'PpYrs', 'num'],
      ['lockout_end', 'LkEnd', 'date'], ['prepay_end', 'PpEnd', 'date'],
      ['prepay_desc', 'Schedule', 'text']]},
    { bg: '#1F4D2A', cols: [
      ['upb_M', 'UPB($M)', 'num'], ['age', 'Age', 'num'], ['mtm', 'MTM', 'num'],
      ['msle', 'MSLE', 'num'], ['burn_ratio', 'Burn', 'num'],
      ['grf_bps', 'GrossBp', 'num'], ['ppp', 'PPP', 'num'],
      ['net_refi_bps', 'NetBp', 'num']]},
    { bg: '#92400E', cols: [
      ['cohort_cpr', 'CohortCPR%', 'num'],
      ['pred_cpr', 'Pred CPR%', 'num'],
      ['actual_prepay', 'Actual', 'num']]},
  ];

  return (
    <Panel title={`Sample loans: ${sample.length} stratified test-set rows (V8)`}
           subtitle="Cohort assigned per loan, then cohort_sigmoid → cohort_cpr → × structural multipliers (M_age/M_maturity/M_lockout/M_burnout) → pred_cpr. Color cells = each multiplier's contribution beyond cohort_cpr.">

      <div style={{ display: 'flex', gap: 4, marginBottom: 4, color: T.textDim,
                    fontSize: 10, fontFamily: FONT_MONO }}>
        <span style={{ background: T.panelLight, padding: '2px 6px', borderRadius: 3 }}>identifiers + cohort</span>
        <span style={{ background: '#0E3A5F', padding: '2px 6px', borderRadius: 3 }}>loan terms</span>
        <span style={{ background: '#5C2A1A', padding: '2px 6px', borderRadius: 3 }}>penalty / lockout</span>
        <span style={{ background: '#1F4D2A', padding: '2px 6px', borderRadius: 3 }}>state at loan-month</span>
        <span style={{ background: '#92400E', padding: '2px 6px', borderRadius: 3 }}>prediction</span>
        <span style={{ background: '#3F0F4F', padding: '2px 6px', borderRadius: 3 }}>structural mult attribution</span>
      </div>

      <div style={{ overflowX: 'auto', maxHeight: 620, overflowY: 'auto',
                    border: `1px solid ${T.border}`, borderRadius: 4 }}>
        <table style={{ width: '100%', borderCollapse: 'collapse',
                        fontFamily: FONT_MONO, fontSize: 10.5 }}>
          <thead>
            <tr>
              {groups.flatMap(g => g.cols.map(([k, lab, fmt]) => (
                <th key={k} style={{ ...headTd, background: g.bg,
                                     textAlign: fmt === 'text' ? 'left' : 'right' }}
                    onClick={() => flipSort(k)}>{lab}{arrow(k)}</th>
              )))}
              {multNames.map(name => (
                <th key={'attr_' + name} style={{ ...headTd, textAlign: 'right',
                    background: '#3F0F4F', borderLeft: `1px solid ${T.border}` }}
                    onClick={() => flipSort('attr_' + name)}
                    title={`Attribution for ${name} in CPR pp`}>
                  {name.replace('M_', '')}{arrow('attr_' + name)}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sorted.map((row, i) => {
              const renderCell = ([k, _, fmt]) => {
                const v = row[k];
                const display = (v == null || v === '')
                  ? '—'
                  : (fmt === 'num'
                      ? (typeof v === 'number'
                          ? (Number.isInteger(v) ? v : v.toFixed(2))
                          : v)
                      : v);
                const cellStyle = { ...cellTd,
                  textAlign: fmt === 'text' ? 'left' : 'right',
                  whiteSpace: 'nowrap' };
                if (k === 'pred_cpr')
                  return <td key={k} style={{ ...cellStyle, color: T.accent, fontWeight: 600 }}>
                    {row.pred_cpr.toFixed(2)}
                  </td>;
                if (k === 'cohort_cpr')
                  return <td key={k} style={{ ...cellStyle, color: T.yellow }}>
                    {row.cohort_cpr.toFixed(2)}
                  </td>;
                if (k === 'actual_prepay')
                  return <td key={k} style={{ ...cellStyle, textAlign: 'center',
                    color: row.actual_prepay ? T.green : T.textDim }}>
                    {row.actual_prepay ? '✓' : '·'}
                  </td>;
                if (k === 'loan_id')
                  return <td key={k} style={{ ...cellStyle, color: T.text }}>{display}</td>;
                if (k === 'cohort_id')
                  return <td key={k} style={{ ...cellStyle, color: T.purple,
                                              fontWeight: 500 }}>{display}</td>;
                return <td key={k} style={cellStyle}>{display}</td>;
              };
              return (
                <tr key={i} style={{ background: i % 2 ? T.panel : 'transparent',
                                      color: T.textDim }}>
                  {groups.flatMap(g => g.cols).map(renderCell)}
                  {multNames.map(name => {
                    const v = row.attribution[name];
                    return (
                      <td key={name} style={{ ...cellTd, textAlign: 'right',
                                              color: attrColor(v),
                                              borderLeft: `1px solid ${T.border}` }}
                          title={`${name}=${(row.multipliers[name] || 0).toFixed(3)}`}>
                        {(v >= 0 ? '+' : '') + v.toFixed(2)}
                      </td>
                    );
                  })}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </Panel>
  );
}


