// ============================================================================
// Age Ramps tab — V8.1 visualization of per-cohort aging shape
// ============================================================================
function TabAgeRamps({ md }) {
  const cohorts = md.cohort_definitions || [];
  const ageGrids = md.cohort_age_ramp_grids || {};
  const knotsX = md.age_ramp_knots_x || [0, 24, 96, 240];
  const [view, setView] = useState('grid');         // 'grid' or 'overlay'
  const [groupBy, setGroupBy] = useState('age');    // 'age' (color by age_bucket) or 'cohort'

  // For each cohort: combine fitted ramp (from cohort_age_ramp_grids) +
  // empirical scatter (from cohort_definitions[].age_scatter)
  const data = useMemo(() => cohorts.map((c, i) => {
    const grid = ageGrids[c.cohort_id] || [];
    const ageBucket = c.axes?.age_bucket || 'aged';
    const color = (groupBy === 'age')
      ? (AGE_BUCKET_COLORS[ageBucket] || COHORT_COLORS[i % COHORT_COLORS.length])
      : COHORT_COLORS[i % COHORT_COLORS.length];
    return {
      cohort: c, color, ageBucket,
      gridLine: grid.map(p => ({ x: p.age, y: p.ramp_y })),
      scatter: (c.age_scatter || []).map(s => ({ x: s.bin_mid_age, y: s.ramp_y, n: s.n })),
      knot_points: knotsX.map((x, k) => ({ x, y: c.params?.age_knots_y?.[k] || 1.0 })),
    };
  }), [cohorts, ageGrids, knotsX, groupBy]);

  if (!cohorts.length) {
    return <Panel title="Age Ramps">
      <div style={{color: T.textDim}}>No cohort_definitions in artifact.</div>
    </Panel>;
  }

  return (
    <Panel title={`Per-cohort aging ramps (V8.1 native age dimension)`}
           subtitle={`Each panel = one cohort's fitted age ramp on top of its sigmoid (anchor knot at age=96m, fixed at 1.0). Dots = empirical residual ratio (actual_smm / sigmoid_pred) per age bin. Cohort knots at ${knotsX.join(', ')} months.`}>

      <div style={{ display: 'flex', gap: 8, marginBottom: 12, alignItems: 'center' }}>
        <span style={{ color: T.textDim, fontFamily: FONT_MONO, fontSize: 11 }}>view:</span>
        {[['grid', 'Small multiples'], ['overlay', 'All cohorts overlay']].map(([k, lab]) => (
          <button key={k} onClick={() => setView(k)} style={{
            background: view === k ? T.accent : T.panelLight,
            color: view === k ? T.bg : T.text,
            border: 'none', borderRadius: 4, padding: '4px 12px',
            fontFamily: FONT_MONO, fontSize: 11, cursor: 'pointer',
          }}>{lab}</button>
        ))}
        <span style={{ color: T.textDim, fontFamily: FONT_MONO, fontSize: 11, marginLeft: 16 }}>color:</span>
        {[['age', 'By age bucket'], ['cohort', 'By cohort']].map(([k, lab]) => (
          <button key={k} onClick={() => setGroupBy(k)} style={{
            background: groupBy === k ? T.accent : T.panelLight,
            color: groupBy === k ? T.bg : T.text,
            border: 'none', borderRadius: 4, padding: '4px 12px',
            fontFamily: FONT_MONO, fontSize: 11, cursor: 'pointer',
          }}>{lab}</button>
        ))}
        <span style={{ color: T.textDim, marginLeft: 'auto', fontSize: 11 }}>
          {cohorts.length} primary cohorts
        </span>
      </div>

      {view === 'grid' ? (
        <div style={{ display: 'grid',
                      gridTemplateColumns: 'repeat(auto-fit, minmax(360px, 1fr))',
                      gap: 12 }}>
          {data.map(({ cohort, color, ageBucket, gridLine, scatter, knot_points }) => (
            <div key={cohort.cohort_id}
                 style={{ background: T.panelLight, padding: 8, borderRadius: 6 }}>
              <div style={{ color: T.text, fontSize: 12, fontWeight: 600,
                            marginBottom: 2, fontFamily: FONT_MONO }}>
                {cohort.cohort_id}
                <span style={{ marginLeft: 8, color: AGE_BUCKET_COLORS[ageBucket] || T.textDim,
                                 fontSize: 10 }}>[{ageBucket}]</span>
              </div>
              <div style={{ color: T.textDim, fontSize: 10,
                            fontFamily: FONT_MONO, marginBottom: 4 }}>
                n={(cohort.n || 0).toLocaleString()} · events={cohort.n_events} ·{' '}
                knot_y=[{(cohort.params?.age_knots_y || []).map(y => y.toFixed(2)).join(', ')}]
              </div>
              <ResponsiveContainer width="100%" height={200}>
                <ComposedChart margin={{ top: 4, right: 12, bottom: 4, left: 0 }}>
                  <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
                  <XAxis dataKey="x" type="number" stroke={T.textDim}
                         tick={{ fontFamily: FONT_MONO, fontSize: 10 }}
                         domain={[0, 360]}
                         label={{ value: 'loan_age_months', position: 'insideBottom',
                                  fill: T.textDim, fontSize: 9, offset: -2 }} />
                  <YAxis stroke={T.textDim} tick={{ fontFamily: FONT_MONO, fontSize: 10 }}
                         domain={[0, 'dataMax']} />
                  <Tooltip {...tooltipStyle}
                           formatter={(v, n, p) =>
                             [`${v.toFixed(3)}`, n === 'fitted' ? 'fitted ramp_y' :
                                                  n === 'knots' ? 'knot' :
                                                  `empirical (n=${p.payload.n})`]} />
                  <ReferenceLine y={1} stroke={T.textDim} strokeDasharray="2 2" />
                  <Scatter name="empirical" dataKey="y" data={scatter} fill={color}
                           shape="circle" />
                  <Line name="fitted" type="monotone" dataKey="y" data={gridLine}
                        stroke={color} strokeWidth={2} dot={false} />
                  <Scatter name="knots" dataKey="y" data={knot_points}
                           fill={T.text} shape="diamond" />
                </ComposedChart>
              </ResponsiveContainer>
            </div>
          ))}
        </div>
      ) : (
        <div>
          <ResponsiveContainer width="100%" height={520}>
            <LineChart margin={{ top: 16, right: 16, bottom: 16, left: 8 }}>
              <CartesianGrid stroke={T.grid} strokeDasharray="3 3" />
              <XAxis dataKey="x" type="number" stroke={T.textDim}
                     tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                     domain={[0, 360]}
                     label={{ value: 'loan_age_months',
                              position: 'insideBottom', fill: T.textDim,
                              fontSize: 11, offset: -8 }} />
              <YAxis stroke={T.textDim}
                     tick={{ fontFamily: FONT_MONO, fontSize: 11 }}
                     domain={[0, 'dataMax']}
                     label={{ value: 'age_ramp multiplier (anchor=1.0 at age 96m)',
                              angle: -90, position: 'insideLeft',
                              fill: T.textDim, fontSize: 11 }} />
              <Tooltip {...tooltipStyle} />
              <ReferenceLine y={1} stroke={T.textDim} strokeDasharray="2 2" />
              {data.map(({ cohort, color, gridLine }) => (
                <Line key={cohort.cohort_id}
                      name={cohort.cohort_id}
                      type="monotone" dataKey="y" data={gridLine}
                      stroke={color} strokeWidth={2} dot={false} />
              ))}
            </LineChart>
          </ResponsiveContainer>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, marginTop: 8 }}>
            {data.map(({ cohort, color }) => (
              <div key={cohort.cohort_id} style={{ display: 'flex',
                                                     alignItems: 'center', gap: 4,
                                                     fontFamily: FONT_MONO, fontSize: 11,
                                                     color: T.textDim }}>
                <span style={{ width: 16, height: 3, background: color,
                               display: 'inline-block' }} />
                {cohort.cohort_id}
              </div>
            ))}
          </div>
        </div>
      )}
    </Panel>
  );
}


// ============================================================================
// Top-level shell
// ============================================================================
const TABS = [
  { key: 'overview',   label: 'Overview',         render: TabOverview },
  { key: 'scurves',    label: 'Cohort S-curves',  render: TabCohortSCurves },
  { key: 'ageramps',   label: 'Age Ramps',        render: TabAgeRamps },
  { key: 'browser',    label: 'Cohort Browser',   render: TabCohortBrowser },
  { key: 'historical', label: 'Historical fits',  render: TabHistorical },
  { key: 'calibration',label: 'Calibration',      render: TabCalibration },
  { key: 'cohorts',    label: 'Cohort cuts',      render: TabCohortCuts },
  { key: 'samples',    label: 'Sample Loans',     render: TabSampleLoans },
  { key: 'h2h',        label: 'V8 vs V9',         render: TabH2H },
  { key: 'bench',      label: 'Benchmarks',       render: TabBenchmarks },
];

export default function V8Dashboard() {
  const [tab, setTab] = useState('scurves');     // headline tab on entry
  const md = MODEL_DATA_V9;
  const mdV8 = MODEL_DATA_V8;
  const Tab = TABS.find(t => t.key === tab)?.render || TabOverview;

  if (md._placeholder) {
    return (
      <div style={{ background: T.bg, color: T.text, padding: 24,
                    fontFamily: FONT_SANS, minHeight: '100vh' }}>
        <h1>V8 dashboard — data not yet emitted</h1>
        <pre style={{ background: T.panel, padding: 12, borderRadius: 6,
                      fontFamily: FONT_MONO, fontSize: 12 }}>
{`Run: GNMA_PANEL_PARQUET=working/gnma_mf_panel.parquet python3 train_v9.py --emit-dashboard`}
        </pre>
      </div>
    );
  }

  return (
    <div style={{ background: T.bg, color: T.text, fontFamily: FONT_SANS,
                  minHeight: '100vh', padding: 16 }}>
      <header style={{ marginBottom: 16 }}>
        <div style={{ display: 'flex', alignItems: 'baseline', gap: 12 }}>
          <h1 style={{ margin: 0, fontSize: 22, fontWeight: 600 }}>
            V9 Voluntary Prepayment Model
          </h1>
          <span style={{ color: T.textDim, fontFamily: FONT_MONO, fontSize: 11 }}>
            cohort-based S-curve · {md.metadata?.n_cohorts_fit} primary cohorts ·
            test AUC {md.metadata?.test_auc?.toFixed(4)}
            <span style={{ color: (md.metadata?.max_cpr_full_panel || 0) < 90 ? T.green : T.red,
                            marginLeft: 8 }}>
              (max pred CPR: {(md.metadata?.max_cpr_full_panel || 0).toFixed(1)}%)
            </span>
          </span>
        </div>
      </header>

      <nav style={{ display: 'flex', flexWrap: 'wrap', gap: 4, marginBottom: 16 }}>
        {TABS.map(t => (
          <button key={t.key} onClick={() => setTab(t.key)}
                  style={{ background: tab === t.key ? T.accent : T.panel,
                            color: tab === t.key ? T.bg : T.text,
                            border: `1px solid ${T.border}`, borderRadius: 4,
                            padding: '6px 12px',
                            fontFamily: FONT_MONO, fontSize: 11,
                            cursor: 'pointer',
                            fontWeight: tab === t.key ? 600 : 400 }}>
            {t.label}
          </button>
        ))}
      </nav>

      <main><Tab md={md} mdV8={mdV8} /></main>

      <footer style={{ marginTop: 24, color: T.textDim, fontFamily: FONT_MONO, fontSize: 10 }}>
        Built from model_data_v9.json + model_data_v7.json. Refresh:
        <span style={{ marginLeft: 4 }}>python3 train_v9.py --emit-dashboard</span>
      </footer>
    </div>
  );
}
